def gen(rng, size):
    import string
    alpha = 'abc'
    s = ''.join(rng.choice(alpha) for _ in range(rng.randint(1, 6)))
    words = []
    for _ in range(max(1, size)):
        L = rng.randint(1, 6)
        if rng.random() < 0.5:
            w = s[:min(L, len(s))]
            if not w:
                w = rng.choice(alpha)
        else:
            w = ''.join(rng.choice(alpha) for _ in range(L))
        words.append(w)
    return [words, s]

